    ["Hover for dungeon teleports"] = "Pasar el cursor para teletransportes de mazmorra",
    ["How Second Wind charges are shown: a mini bar below the vigor bar, pips above it, a text readout below it, or hidden entirely."] = "Cómo se muestran las cargas de Segundo aliento: una mini barra debajo de la barra de vigor, puntos encima, un texto debajo o completamente oculto.",
    ["How damage / healing values are formatted in row text and tooltips."] = "Cómo se formatean los valores de daño/sanación en el texto de fila y los tooltips.",
    ["How do I move and resize frames?"] = "¿Cómo muevo y redimensiono marcos?",
    ["How do I report a bug or get help?"] = "¿Cómo reporto un error o pido ayuda?",
    ["How do I reset everything to defaults?"] = "¿Cómo restablezco todo a los valores predeterminados?",
    ["How do I set up keybinds?"] = "¿Cómo configuro las asignaciones de teclas?",
    ["How each enemy's forces contribution is shown next to its nameplate."] = "Cómo se muestra la contribución de fuerzas de cada enemigo junto a su placa de nombre.",
    ["How fast the active glow animates."] = "Qué tan rápido anima el brillo activo.",
