    ["Stored but not joined"] = "Guardado pero no unido",
    ["Stored exclusion for '%s'. Disable to remove from the persistent exclusion set."] = "Exclusión guardada para '%s'. Desactívala para quitarla del conjunto persistente de exclusión.",
    ["Strength"] = "Fuerza",
    ["Stretch bars to match the width of the frame they anchor to (e.g. the player frame)."] = "Estira las barras para que coincidan con el ancho del marco al que se anclan (p. ej., el marco del jugador).",
