    ["Thick Outline"] = "Contorno grueso",
    ["Thickness"] = "Grosor",
    ["Thickness of each Pixel Glow line."] = "Grosor de cada línea de Pixel Glow.",
    ["Thickness of each glow line. Only used by Pixel Glow."] = "Grosor de cada línea de brillo. Solo usado por Pixel Glow.",
    ["Thickness of the bar's border in pixels. 0 removes the border entirely."] = "Grosor del borde de la barra en píxeles. 0 quita el borde por completo.",
    ["Thickness of the bar's screen-inner edge border. Set to 0 to hide it."] = "Grosor del borde del borde interno de la barra. Establece 0 para ocultarlo.",
    ["Thickness of the border drawn around buff and debuff icons."] = "Grosor del borde dibujado alrededor de los iconos de beneficio y perjuicio.",
