    ["Thickness of the lines in the Pixel glow style."] = "Grosor de las líneas en el estilo de brillo Pixel.",
    ["Thickness of the minimap datatext border. Set to 0 to hide it."] = "Grosor del borde del datatext del minimapa. Establece 0 para ocultarlo.",
    ["Thickness of the outline drawn around each crosshair line. 0 disables the outline."] = "Grosor del contorno dibujado alrededor de cada línea de la mira. 0 desactiva el contorno.",
    ["Thickness of the suggestion border in pixels."] = "Grosor del borde de sugerencia en píxeles.",
    ["Thickness of the tick markers, in pixels."] = "Grosor de los marcadores de tic, en píxeles.",
    ["Thickness of the tooltip border in pixels."] = "Grosor del borde del tooltip en píxeles.",
    ["Thickness of the tracker container border. Set to 0 to hide the border."] = "Grosor del borde del contenedor del rastreador. Establece 0 para ocultar el borde.",
    ["Thickness of the tracking bar border in pixels. 0 uses the automatic pixel-perfect value."] = "Grosor del borde de la barra de seguimiento en píxeles. 0 usa el valor automático de píxel perfecto.",
